import { BiCodeAlt as SkillsIcon } from "react-icons/bi";
import { useTranslations } from "next-intl";

import SectionHeading from "@/common/components/elements/SectionHeading";
import SectionSubHeading from "@/common/components/elements/SectionSubHeading";
import { IconResolver } from "@/common/utils/iconResolver";

export type SkillItem = {
  id: number;
  title: string;
  category: string;
  imageSrc: string;
  isCoreSkill: boolean;
  color: string;
  tags?: string[];
};

interface SkillListProps {
  skills: SkillItem[];
}

const SkillList = ({ skills }: SkillListProps) => {
  const t = useTranslations("HomePage");

  // Keep only the core skills or active ones
  const activeSkills = skills?.filter(skill => skill.isCoreSkill) || [];

  return (
    <section className="space-y-6">
      <div className="space-y-2">
        <SectionHeading title={t("skills.title")} icon={<SkillsIcon />} />
        <SectionSubHeading>
          <p>{t("skills.sub_title")}</p>
        </SectionSubHeading>
      </div>

      <div className="grid w-full grid-cols-6 gap-x-[1em] gap-y-[2.7em] py-2 md:grid-cols-10 lg:grid-cols-11">
        {activeSkills.map((skill, index) => (
          <div
            key={index}
            className="flex items-center justify-center p-2 rounded-full transition-all duration-300 hover:scale-110 tooltip-container"
          >
            <div title={skill.title} style={{ color: skill.color || "currentColor" }}>
              <IconResolver iconNameOrUrl={skill.imageSrc} size={28} />
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default SkillList;
